import anthropic
import base64
from PIL import ImageGrab
import io

client = anthropic.Anthropic()

def capture_screen_b64() -> str:
    img = ImageGrab.grab()
    buf = io.BytesIO()
    img.save(buf, format="PNG")
    return base64.standard_b64encode(buf.getvalue()).decode()

# First turn: give the model its initial task + current screen
initial_screenshot = capture_screen_b64()

response = client.beta.messages.create(
    model="claude-opus-4-5",
    max_tokens=4096,
    tools=[
        {
            "type": "computer_20250124",
            "name": "computer",
            "display_width_px": 1920,
            "display_height_px": 1080,
        }
    ],
    messages=[
        {
            "role": "user",
            "content": [
                {
                    "type": "image",
                    "source": {
                        "type": "base64",
                        "media_type": "image/png",
                        "data": initial_screenshot,
                    },
                },
                {
                    "type": "text",
                    "text": (
                        "Open Firefox, navigate to https://example.com, "
                        "and take a screenshot when the page has loaded."
                    ),
                },
            ],
        }
    ],
    betas=["computer-use-2025-01-24"],
)

# Inspect response structure
for block in response.content:
    print(block.type, getattr(block, "text", None) or getattr(block, "input", None))

import anthropic, base64, time
from PIL import ImageGrab
import io, pyautogui

client = anthropic.Anthropic()

def run(task: str, max_steps: int = 30) -> str:
    def snap():
        img = ImageGrab.grab()
        buf = io.BytesIO()
        img.save(buf, format="PNG")
        return base64.standard_b64encode(buf.getvalue()).decode()

    messages = [{"role": "user", "content": task}]

    for _ in range(max_steps):
        # Prepend current screenshot to messages
        messages.append({
            "role": "user",
            "content": [
                {"type": "image",
                 "source": {"type": "base64", "media_type": "image/png", "data": snap()}},
                {"type": "text", "text": "Current screen. Continue."}
            ],
        })

        resp = client.beta.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            tools=[{"type": "computer_20250124", "name": "computer",
                    "display_width_px": 1920, "display_height_px": 1080}],
            messages=messages,
            betas=["computer-use-2025-01-24"],
        )

        messages.append({"role": "assistant", "content": resp.content})

        tool_uses = [b for b in resp.content if b.type == "tool_use"]
        if not tool_uses:
            # Done — return first text block
            return next((b.text for b in resp.content if hasattr(b, "text")), "done")

        tool_results = []
        for tu in tool_uses:
            action = tu.input
            sub = action.get("action")
            coord = action.get("coordinate", [0, 0])

            if sub == "screenshot":
                pass  # result will be snapshot below
            elif sub == "left_click":
                pyautogui.click(coord[0], coord[1])
            elif sub == "double_click":
                pyautogui.doubleClick(coord[0], coord[1])
            elif sub == "right_click":
                pyautogui.rightClick(coord[0], coord[1])
            elif sub == "type":
                pyautogui.typewrite(action["text"], interval=0.04)
            elif sub == "key":
                pyautogui.hotkey(*action["key"].split("+"))
            elif sub == "scroll":
                clicks = 3 if action.get("direction") == "up" else -3
                pyautogui.scroll(clicks, x=coord[0], y=coord[1])
            elif sub == "drag":
                end = action["endCoordinate"]
                pyautogui.dragTo(end[0], end[1], duration=0.4, button="left")

            time.sleep(0.35)

            tool_results.append({
                "type": "tool_result",
                "tool_use_id": tu.id,
                "content": [{"type": "image",
                             "source": {"type": "base64",
                                        "media_type": "image/png",
                                        "data": snap()}}],
            })

        messages.append({"role": "user", "content": tool_results})

    return "max_steps reached"

if __name__ == "__main__":
    result = run("Open the calculator application and compute 47 * 83.")
    print(result)
